import type { Metadata } from "next";
import Receiving from "./Receiving";

export const metadata: Metadata = {
  title: "入荷検品 / 受領 | ぐんじょうストア 在庫",
  description:
    "入荷検品・受領の画面。発注番号で発注書を呼び出し、仕入先 / 発注日 / 入荷予定日 / 倉庫・店舗 / 明細行数を表示。届いた商品のバーコード（JAN）をスキャンして発注明細に照合し、該当行の検品数量を1点ずつ加算（「〇〇 を1点 検品」と読み上げ、発注に無い商品はエラー読み上げ）。商品名 / SKU・JAN / 発注数量 / 検品数量（スキャン駆動・手修正可）/ 差異（＝検品−発注。一致 / 過剰入荷 / 不足）/ 状態を並べた入荷明細グリッド、良品・不良の品質区分と生鮮品のロット番号・賞味期限の取得、検品≠発注時に差異理由（品切れ / 誤出荷 / 破損 / 入荷遅延）を要求する差異処理ゲート、入荷確定（全行の検品または差異理由が揃うまでブロック）/ 一時保存 / 受領書印刷を備えた受領ツールです。",
};

export default function ReceivingPage() {
  return <Receiving />;
}

// ─────────────────────────────────────────────────────────────────────────────
// 入荷検品 / 受領 — domain model & pure logic
// PO (発注書) lookup → barcode scan match → 検品数量 / 差異 / ロット・賞味期限 → 受領
// ─────────────────────────────────────────────────────────────────────────────

/** 差異理由 — required when 検品 ≠ 発注 before accepting. */
export type DiscrepancyReason = "shortage" | "misship" | "damage" | "delay";

export const DISCREPANCY_REASON_LABEL: Record<DiscrepancyReason, string> = {
  shortage: "品切れ（先方在庫不足）",
  misship: "誤出荷",
  damage: "破損・汚損",
  delay: "入荷遅延（分納）",
};

export const DISCREPANCY_REASON_OPTIONS: { value: DiscrepancyReason; label: string }[] = (
  Object.keys(DISCREPANCY_REASON_LABEL) as DiscrepancyReason[]
).map((value) => ({ value, label: DISCREPANCY_REASON_LABEL[value] }));

/** 品質区分 — per line. 不良 forces a 差異理由 even if counts match. */
export type Quality = "good" | "damaged";

export const QUALITY_LABEL: Record<Quality, string> = {
  good: "良品",
  damaged: "不良（破損・汚損・期限切れ）",
};

/** A purchase-order line as it arrives from the PO + the staffer's inspection state. */
export interface ReceivingLine {
  id: string;
  name: string;
  sku: string;
  jan: string; // barcode scanned to match
  /** 発注数量 — ordered. */
  ordered: number;
  /** 検品数量 — scan-driven, also editable. */
  inspected: number;
  /** 仕入原価 (単価, 税抜) — for ¥ summary. */
  unitCost: number;
  /** Perishable lines must capture ロット番号 / 賞味期限. */
  perishable: boolean;
  lot: string;
  /** 賞味期限 — ISO yyyy-mm-dd or "". */
  expiry: string;
  quality: Quality;
  reason: DiscrepancyReason | "";
}

export interface PurchaseOrder {
  poNumber: string; // 発注番号
  supplier: string; // 仕入先
  orderedDate: string; // 発注日
  expectedDate: string; // 入荷予定日
  warehouse: string; // 倉庫・店舗
  lines: ReceivingLine[];
}

// ─── derived per-line ────────────────────────────────────────────────────────

/** 差異 = 検品 − 発注 (signed: + 過剰 / − 不足 / 0 一致). */
export function lineDelta(l: ReceivingLine): number {
  return l.inspected - l.ordered;
}

export type LineState = "pending" | "match" | "over" | "short" | "damaged";

export function lineState(l: ReceivingLine): LineState {
  if (l.quality === "damaged") return "damaged";
  if (l.inspected === 0) return "pending";
  const d = lineDelta(l);
  if (d === 0) return "match";
  return d > 0 ? "over" : "short";
}

export const LINE_STATE_LABEL: Record<LineState, string> = {
  pending: "未検品",
  match: "一致",
  over: "過剰入荷",
  short: "不足",
  damaged: "不良あり",
};

/** A reason is required when counts differ OR the line is flagged damaged. */
export function needsReason(l: ReceivingLine): boolean {
  return lineDelta(l) !== 0 || l.quality === "damaged";
}

/** Perishable lines must have lot + expiry once something is inspected. */
export function needsLotExpiry(l: ReceivingLine): boolean {
  return l.perishable && l.inspected > 0;
}

export function lineCost(l: ReceivingLine): number {
  return l.unitCost * l.inspected;
}

// ─── receipt-level totals ────────────────────────────────────────────────────

export function totalOrdered(lines: ReceivingLine[]): number {
  return lines.reduce((s, l) => s + l.ordered, 0);
}
export function totalInspected(lines: ReceivingLine[]): number {
  return lines.reduce((s, l) => s + l.inspected, 0);
}
/** Count of lines whose 検品 ≠ 発注 OR flagged 不良 (= the discrepancy-row count). */
export function discrepancyCount(lines: ReceivingLine[]): number {
  return lines.filter((l) => needsReason(l)).length;
}
export function totalCost(lines: ReceivingLine[]): number {
  return lines.reduce((s, l) => s + lineCost(l), 0);
}

// ─── accept-gate validation ──────────────────────────────────────────────────

export interface LineProblem {
  lineId: string;
  message: string;
}

/**
 * Every line must be either inspected-and-reconciled or explicitly acknowledged:
 *  - 検品=0 and not flagged → 未検品 (must touch every line at least once).
 *  - 検品≠発注 or 不良 → 差異理由 required.
 *  - perishable+inspected → ロット番号 + 賞味期限 required.
 */
export function validate(lines: ReceivingLine[]): LineProblem[] {
  const problems: LineProblem[] = [];
  for (const l of lines) {
    if (l.inspected === 0 && l.quality === "good") {
      problems.push({ lineId: l.id, message: `${l.name}：未検品です（検品 または 差異理由が必要）` });
      continue;
    }
    if (needsReason(l) && l.reason === "") {
      problems.push({ lineId: l.id, message: `${l.name}：差異理由を選択してください` });
    }
    if (needsLotExpiry(l)) {
      if (l.lot.trim() === "")
        problems.push({ lineId: l.id, message: `${l.name}：ロット番号を入力してください` });
      if (l.expiry === "")
        problems.push({ lineId: l.id, message: `${l.name}：賞味期限を入力してください` });
    }
  }
  return problems;
}

export function canAccept(lines: ReceivingLine[]): boolean {
  return lines.length > 0 && validate(lines).length === 0;
}

// ─── barcode scan resolution ─────────────────────────────────────────────────

export type ScanOutcome =
  | { kind: "match"; lineId: string; name: string; inspected: number; ordered: number }
  | { kind: "notfound"; code: string };

/** Normalize a scanned code: trim, strip spaces/hyphens (scanners sometimes inject them). */
export function normalizeCode(raw: string): string {
  return raw.trim().replace(/[\s-]/g, "");
}

/** Resolve a normalized code to a PO line by exact JAN match. */
export function matchScan(lines: ReceivingLine[], code: string): ScanOutcome {
  const norm = normalizeCode(code);
  const line = lines.find((l) => l.jan === norm);
  if (!line) return { kind: "notfound", code: norm };
  const inspected = line.inspected + 1;
  return { kind: "match", lineId: line.id, name: line.name, inspected, ordered: line.ordered };
}

// ─── seed purchase orders (lookup table) ─────────────────────────────────────

function line(
  id: string,
  name: string,
  sku: string,
  jan: string,
  ordered: number,
  unitCost: number,
  perishable = false,
): ReceivingLine {
  return {
    id,
    name,
    sku,
    jan,
    ordered,
    inspected: 0,
    unitCost,
    perishable,
    lot: "",
    expiry: "",
    quality: "good",
    reason: "",
  };
}

export const PURCHASE_ORDERS: PurchaseOrder[] = [
  {
    poNumber: "PO-2026-0612",
    supplier: "丸三食品 株式会社",
    orderedDate: "2026-06-18",
    expectedDate: "2026-06-23",
    warehouse: "本店 バックヤード",
    lines: [
      line("l1", "有機ほうじ茶 500ml", "BEV-HJ-500", "4901234567894", 24, 88, true),
      line("l2", "瀬戸内レモンサイダー 350ml", "BEV-LM-350", "4901234560015", 36, 72, true),
      line("l3", "深煎りドリップコーヒー 8袋", "COF-DR-08", "4909876543210", 12, 260),
      line("l4", "国産はちみつ 200g", "GRO-HN-200", "4900112233445", 18, 540, true),
      line("l5", "白だし 500ml", "GRO-SD-500", "4905566778899", 24, 198),
      line("l6", "ステンレスボトル 600ml", "GDS-BT-600", "4903344556677", 6, 1280),
    ],
  },
  {
    poNumber: "PO-2026-0588",
    supplier: "北陸雑貨 卸",
    orderedDate: "2026-06-15",
    expectedDate: "2026-06-22",
    warehouse: "本店 バックヤード",
    lines: [
      line("m1", "ヒノキまな板 中", "KIT-CB-M", "4902001112223", 8, 1450),
      line("m2", "綿100% ふきん 5枚組", "KIT-FK-05", "4902003334445", 20, 380),
      line("m3", "珪藻土コースター 4枚", "KIT-CS-04", "4902005556667", 15, 620),
    ],
  },
];

/** Look up a PO by 発注番号 (case-insensitive, also accepts a scanned PO label). */
export function lookupPO(value: string): PurchaseOrder | undefined {
  const v = value.trim().toUpperCase();
  return PURCHASE_ORDERS.find((po) => po.poNumber.toUpperCase() === v);
}

/** Fresh deep copy of a PO's lines so editing never mutates the seed table. */
export function cloneLines(po: PurchaseOrder): ReceivingLine[] {
  return po.lines.map((l) => ({ ...l }));
}

"use client";

import * as React from "react";
import { ja } from "date-fns/locale";
import {
  IconBarcode,
  IconScan,
  IconSearch,
  IconBuildingWarehouse,
  IconTruckDelivery,
  IconCalendarEvent,
  IconPackageImport,
  IconClipboardCheck,
  IconDeviceFloppy,
  IconPrinter,
  IconAlertTriangle,
  IconCircleCheck,
  IconX,
  IconList,
} from "@tabler/icons-react";
import {
  Alert,
  AlertDescription,
  AlertTitle,
  Badge,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  DatePicker,
  Delta,
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  EditableDataTable,
  Input,
  Label,
  NumberInput,
  RevealSection,
  Select,
  Separator,
  Statistic,
  ToggleGroup,
  ToggleGroupItem,
  formatCurrency,
  formatNumber,
  type EditableColumn,
  type BadgeProps,
} from "@gunjo/ui";

import {
  DISCREPANCY_REASON_OPTIONS,
  PURCHASE_ORDERS,
  canAccept,
  cloneLines,
  discrepancyCount,
  lineDelta,
  lineState,
  LINE_STATE_LABEL,
  lookupPO,
  matchScan,
  needsLotExpiry,
  needsReason,
  totalCost,
  totalInspected,
  totalOrdered,
  validate,
  type DiscrepancyReason,
  type LineState,
  type PurchaseOrder,
  type Quality,
  type ReceivingLine,
} from "./data";

const yen = (n: number) => formatCurrency(n, { maximumFractionDigits: 0 });

type Phase = "lookup" | "inspecting" | "done";

interface ScanEvent {
  id: number;
  kind: "match" | "notfound";
  label: string; // 商品名 or scanned code
  detail: string; // "検品 3 / 発注 24" or "発注に無い商品"
}

const STATE_BADGE_VARIANT: Record<LineState, BadgeProps["variant"]> = {
  pending: "outline",
  match: "success",
  over: "warning",
  short: "warning",
  damaged: "destructive",
};

export default function Receiving() {
  const [phase, setPhase] = React.useState<Phase>("lookup");
  const [poInput, setPoInput] = React.useState("");
  const [lookupError, setLookupError] = React.useState<string | null>(null);

  const [po, setPo] = React.useState<PurchaseOrder | null>(null);
  const [lines, setLines] = React.useState<ReceivingLine[]>([]);

  // scan state
  const [scanInput, setScanInput] = React.useState("");
  const [scanResult, setScanResult] = React.useState<
    { kind: "match"; message: string } | { kind: "notfound"; message: string } | null
  >(null);
  const [scanFeed, setScanFeed] = React.useState<ScanEvent[]>([]);
  const scanRef = React.useRef<HTMLInputElement>(null);
  const feedSeq = React.useRef(0);

  const [showErrors, setShowErrors] = React.useState(false);
  const [receiptOpen, setReceiptOpen] = React.useState(false);
  const [savedAt, setSavedAt] = React.useState<string | null>(null);

  const problems = React.useMemo(() => validate(lines), [lines]);
  const problemByLine = React.useMemo(() => {
    const m = new Map<string, string>();
    for (const p of problems) if (!m.has(p.lineId)) m.set(p.lineId, p.message);
    return m;
  }, [problems]);

  // ─── PO lookup ──────────────────────────────────────────────────────────────
  function resolvePO(value: string) {
    const found = lookupPO(value);
    if (!found) {
      setLookupError(
        `「${value}」に一致する発注書が見つかりません。発注番号（例 PO-2026-0612）を確認してください。`,
      );
      return;
    }
    setPo(found);
    setLines(cloneLines(found));
    setLookupError(null);
    setShowErrors(false);
    setSavedAt(null);
    setScanResult(null);
    setScanFeed([]);
    setPhase("inspecting");
    // focus the scan input once we're in inspecting mode
    window.requestAnimationFrame(() => scanRef.current?.focus());
  }

  // ─── line mutation ────────────────────────────────────────────────────────────
  const patchLine = React.useCallback(
    (id: string, patch: Partial<ReceivingLine>) => {
      setLines((prev) => prev.map((l) => (l.id === id ? { ...l, ...patch } : l)));
    },
    [],
  );

  // ─── barcode scan → match → increment (the centerpiece) ──────────────────────
  function handleScan(e: React.FormEvent) {
    e.preventDefault();
    const raw = scanInput;
    if (raw.trim() === "") return;
    setScanInput("");

    const outcome = matchScan(lines, raw);
    feedSeq.current += 1;
    const seq = feedSeq.current;

    if (outcome.kind === "match") {
      patchLine(outcome.lineId, { inspected: outcome.inspected });
      const msg = `${outcome.name} を1点 検品（検品 ${outcome.inspected} / 発注 ${outcome.ordered}）`;
      setScanResult({ kind: "match", message: msg });
      setScanFeed((prev) =>
        [
          {
            id: seq,
            kind: "match" as const,
            label: outcome.name,
            detail: `検品 ${outcome.inspected} / 発注 ${outcome.ordered}`,
          },
          ...prev,
        ].slice(0, 8),
      );
    } else {
      const msg = `発注に無い商品です（コード ${outcome.code}）。発注書を確認してください。`;
      setScanResult({ kind: "notfound", message: msg });
      setScanFeed((prev) =>
        [
          { id: seq, kind: "notfound" as const, label: outcome.code, detail: "発注に無い商品" },
          ...prev,
        ].slice(0, 8),
      );
    }
    // keep focus so the scan gun can fire again immediately
    window.requestAnimationFrame(() => scanRef.current?.focus());
  }

  // ─── totals ───────────────────────────────────────────────────────────────────
  const ordered = totalOrdered(lines);
  const inspected = totalInspected(lines);
  const discCount = discrepancyCount(lines);
  const cost = totalCost(lines);
  const accepted = phase === "done";

  // ─── accept ───────────────────────────────────────────────────────────────────
  function attemptAccept() {
    if (!canAccept(lines)) {
      setShowErrors(true);
      return;
    }
    setShowErrors(false);
    setPhase("done");
    setReceiptOpen(false);
  }

  function reset() {
    setPhase("lookup");
    setPo(null);
    setLines([]);
    setPoInput("");
    setScanResult(null);
    setScanFeed([]);
    setShowErrors(false);
    setSavedAt(null);
  }

  // ─── receiving-lines grid columns ──────────────────────────────────────────────
  const columns: EditableColumn<ReceivingLine>[] = [
    {
      id: "name",
      header: "商品 / SKU・JAN",
      minWidth: "13rem",
      cell: (row) => (
        <div className="flex flex-col">
          <span className="font-medium leading-snug">{row.name}</span>
          <span className="font-mono text-xs text-muted-foreground tabular-nums">
            {row.sku} · {row.jan}
          </span>
        </div>
      ),
    },
    {
      id: "ordered",
      header: "発注数量",
      align: "center",
      width: "5.5rem",
      cell: (row) => <span className="tabular-nums">{formatNumber(row.ordered)}</span>,
    },
    {
      id: "inspected",
      header: "検品数量",
      align: "center",
      width: "9rem",
      minWidth: "8.5rem",
      cell: (row, ctx) => (
        <NumberInput
          layout="stepper"
          value={row.inspected}
          min={0}
          max={999}
          onValueChange={(n) => patchLine(row.id, { inspected: n })}
          aria-label={`${ctx.ariaLabel}（スキャンで加算・手修正可）`}
          disabled={accepted}
        />
      ),
    },
    {
      id: "delta",
      header: "差異",
      align: "center",
      width: "8rem",
      minWidth: "7rem",
      cell: (row) => {
        if (row.inspected === 0) {
          return <span className="text-xs text-muted-foreground">未検品</span>;
        }
        const d = lineDelta(row);
        // diff is conveyed by sign + text label (一致/過剰/不足), never colour alone.
        return (
          <Delta
            value={d}
            format={(n) => (n === 0 ? "0" : formatNumber(n, { signed: true }))}
            labels={{ positive: "過剰", negative: "不足", zero: "一致" }}
            showLabel
            // over-receipt isn't "good" here → warning, not success.
            tones={{ positive: "warning", negative: "warning", zero: "success" }}
          />
        );
      },
    },
    {
      id: "quality",
      header: "品質",
      align: "center",
      width: "9rem",
      minWidth: "8.5rem",
      cell: (row) => (
        <ToggleGroup
          type="single"
          disallowEmpty
          value={row.quality}
          onValueChange={(v) =>
            patchLine(row.id, { quality: (v || "good") as Quality })
          }
          variant="outline"
          size="sm"
          disabled={accepted}
          aria-label={`${row.name} 品質区分`}
          className="justify-center"
        >
          <ToggleGroupItem value="good" aria-label={`${row.name} 良品`}>
            良品
          </ToggleGroupItem>
          <ToggleGroupItem value="damaged" aria-label={`${row.name} 不良`}>
            不良
          </ToggleGroupItem>
        </ToggleGroup>
      ),
    },
    {
      id: "state",
      header: "状態",
      align: "center",
      width: "6.5rem",
      cell: (row) => {
        const s = lineState(row);
        return <Badge variant={STATE_BADGE_VARIANT[s]}>{LINE_STATE_LABEL[s]}</Badge>;
      },
    },
    {
      id: "reason",
      header: "差異理由 / ロット・賞味期限",
      minWidth: "16rem",
      cell: (row, ctx) => {
        const wantReason = needsReason(row);
        const wantLot = needsLotExpiry(row);
        if (!wantReason && !wantLot) {
          return <span className="text-xs text-muted-foreground">—</span>;
        }
        const reasonMissing = wantReason && row.reason === "";
        return (
          <div className="flex flex-col gap-2">
            {wantReason ? (
              <Select
                value={row.reason}
                onChange={(e) =>
                  patchLine(row.id, { reason: e.target.value as DiscrepancyReason | "" })
                }
                aria-label={`${ctx.ariaLabel}（差異理由）`}
                aria-invalid={showErrors && reasonMissing ? true : undefined}
                disabled={accepted}
                className="h-8"
              >
                <option value="">差異理由を選択</option>
                {DISCREPANCY_REASON_OPTIONS.map((o) => (
                  <option key={o.value} value={o.value}>
                    {o.label}
                  </option>
                ))}
              </Select>
            ) : null}
            {wantLot ? (
              <div className="flex flex-col gap-1.5">
                <Input
                  value={row.lot}
                  onChange={(e) => patchLine(row.id, { lot: e.target.value })}
                  placeholder="ロット番号"
                  aria-label={`${row.name} ロット番号`}
                  aria-invalid={showErrors && row.lot.trim() === "" ? true : undefined}
                  disabled={accepted}
                  className="h-8"
                />
                <DatePicker
                  locale={ja}
                  value={row.expiry ? new Date(`${row.expiry}T00:00:00`) : undefined}
                  onValueChange={(d) =>
                    patchLine(row.id, {
                      expiry: d
                        ? `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(
                            d.getDate(),
                          ).padStart(2, "0")}`
                        : "",
                    })
                  }
                  placeholder="賞味期限 yyyy-mm-dd"
                  calendarLabel={`${row.name} 賞味期限を選択`}
                  disabled={accepted}
                  triggerClassName="h-8"
                />
              </div>
            ) : null}
          </div>
        );
      },
    },
  ];

  function footerCell(col: EditableColumn<ReceivingLine>) {
    if (col.id === "name") return <span className="font-semibold">合計</span>;
    if (col.id === "ordered")
      return <span className="font-semibold tabular-nums">{formatNumber(ordered)}</span>;
    if (col.id === "inspected")
      return <span className="font-semibold tabular-nums">{formatNumber(inspected)}</span>;
    if (col.id === "delta") {
      if (inspected === 0) return <span className="text-muted-foreground">—</span>;
      return (
        <Delta
          value={inspected - ordered}
          format={(n) => (n === 0 ? "0" : formatNumber(n, { signed: true }))}
          labels={{ positive: "過剰", negative: "不足", zero: "一致" }}
          showLabel
          tones={{ positive: "warning", negative: "warning", zero: "success" }}
          className="font-semibold"
        />
      );
    }
    if (col.id === "state")
      return (
        <span className="text-xs font-medium text-muted-foreground tabular-nums">
          差異 {discCount} 件
        </span>
      );
    return null;
  }

  // ─── render ─────────────────────────────────────────────────────────────────
  return (
    <main className="mx-auto flex w-full max-w-6xl flex-col gap-6 p-4 sm:p-6">
      <header className="flex flex-col gap-1">
        <h1 className="flex items-center gap-2 text-2xl font-bold tracking-tight">
          <IconPackageImport className="h-6 w-6 shrink-0" aria-hidden="true" />
          入荷検品 / 受領
        </h1>
        <p className="text-sm text-muted-foreground">
          発注書を呼び出し、届いた商品のバーコードをスキャンして検品 — 検品 vs 発注の差異を確認し、在庫へ受領します。
        </p>
      </header>

      {/* ─── PO lookup ─── */}
      {phase === "lookup" ? (
        <Card>
          <CardHeader>
            <CardTitle as="h2" className="flex items-center gap-2 text-lg">
              <IconSearch className="h-5 w-5" aria-hidden="true" />
              発注書の照合
            </CardTitle>
            <CardDescription>
              発注番号を入力（またはスキャン）して、入荷予定の発注書を呼び出します。
            </CardDescription>
          </CardHeader>
          <CardContent className="flex flex-col gap-4">
            <form
              className="flex flex-col gap-2 sm:flex-row sm:items-end"
              onSubmit={(e) => {
                e.preventDefault();
                if (poInput.trim()) resolvePO(poInput);
              }}
            >
              <div className="flex w-full flex-col gap-1.5">
                <Label htmlFor="po-lookup">発注番号</Label>
                <Input
                  id="po-lookup"
                  value={poInput}
                  onChange={(e) => setPoInput(e.target.value)}
                  placeholder="PO-2026-0612"
                  autoComplete="off"
                  aria-invalid={lookupError ? true : undefined}
                  aria-describedby={lookupError ? "po-lookup-error" : undefined}
                />
              </div>
              <Button type="submit" disabled={!poInput.trim()} className="shrink-0">
                <IconSearch className="h-4 w-4" aria-hidden="true" />
                呼び出す
              </Button>
            </form>

            <div aria-live="assertive">
              {lookupError ? (
                <Alert variant="destructive" id="po-lookup-error">
                  <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
                  <AlertTitle as="h3">発注書が見つかりません</AlertTitle>
                  <AlertDescription>{lookupError}</AlertDescription>
                </Alert>
              ) : null}
            </div>

            <Separator />
            <div className="flex flex-col gap-2">
              <p className="text-xs font-medium text-muted-foreground">入荷予定の発注書</p>
              <ul className="flex flex-col gap-2">
                {PURCHASE_ORDERS.map((p) => (
                  <li key={p.poNumber}>
                    <button
                      type="button"
                      onClick={() => {
                        setPoInput(p.poNumber);
                        resolvePO(p.poNumber);
                      }}
                      className="flex w-full items-center justify-between gap-3 rounded-lg border bg-card p-3 text-left transition-colors hover:bg-muted focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring"
                    >
                      <span className="flex flex-col">
                        <span className="font-mono text-sm font-medium">{p.poNumber}</span>
                        <span className="text-xs text-muted-foreground">
                          {p.supplier} · {p.lines.length} 明細
                        </span>
                      </span>
                      <Badge variant="outline" className="shrink-0">
                        入荷予定 {p.expectedDate}
                      </Badge>
                    </button>
                  </li>
                ))}
              </ul>
            </div>
          </CardContent>
        </Card>
      ) : null}

      {/* ─── inspecting / done ─── */}
      {po ? (
        <>
          {/* PO header */}
          <Card>
            <CardHeader className="pb-4">
              <div className="flex flex-wrap items-start justify-between gap-3">
                <div className="flex flex-col gap-1">
                  <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                    <IconTruckDelivery className="h-5 w-5" aria-hidden="true" />
                    <span className="font-mono">{po.poNumber}</span>
                  </CardTitle>
                  <CardDescription>{po.supplier}</CardDescription>
                </div>
                {accepted ? (
                  <Badge variant="success" className="h-6">
                    <IconCircleCheck className="mr-1 h-3.5 w-3.5" aria-hidden="true" />
                    受領完了
                  </Badge>
                ) : (
                  <Badge variant="info" className="h-6">
                    検品中
                  </Badge>
                )}
              </div>
            </CardHeader>
            <CardContent>
              <dl className="grid grid-cols-2 gap-x-4 gap-y-3 text-sm sm:grid-cols-4">
                <div className="flex flex-col">
                  <dt className="text-xs text-muted-foreground">発注日</dt>
                  <dd className="tabular-nums">{po.orderedDate}</dd>
                </div>
                <div className="flex flex-col">
                  <dt className="flex items-center gap-1 text-xs text-muted-foreground">
                    <IconCalendarEvent className="h-3.5 w-3.5" aria-hidden="true" />
                    入荷予定日
                  </dt>
                  <dd className="tabular-nums">{po.expectedDate}</dd>
                </div>
                <div className="flex flex-col">
                  <dt className="flex items-center gap-1 text-xs text-muted-foreground">
                    <IconBuildingWarehouse className="h-3.5 w-3.5" aria-hidden="true" />
                    倉庫・店舗
                  </dt>
                  <dd>{po.warehouse}</dd>
                </div>
                <div className="flex flex-col">
                  <dt className="text-xs text-muted-foreground">明細行数</dt>
                  <dd className="tabular-nums">{po.lines.length} 行</dd>
                </div>
              </dl>
            </CardContent>
          </Card>

          {/* KPI summary */}
          <div className="grid grid-cols-2 gap-3 sm:grid-cols-4">
            <Statistic label="発注合計" value={`${formatNumber(ordered)} 点`} />
            <Statistic
              label="検品合計"
              value={`${formatNumber(inspected)} 点`}
              hint={`発注比 ${ordered ? Math.round((inspected / ordered) * 100) : 0}%`}
            />
            <Statistic
              label="差異件数"
              value={`${formatNumber(discCount)} 件`}
              trend={discCount > 0 ? "down" : "flat"}
              tone={discCount > 0 ? "negative" : "neutral"}
              change={discCount > 0 ? "要差異理由" : "—"}
            />
            <Statistic label="検品 仕入原価" value={yen(cost)} />
          </div>

          {/* scan input — the centerpiece */}
          {!accepted ? (
            <Card>
              <CardHeader className="pb-3">
                <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                  <IconScan className="h-5 w-5" aria-hidden="true" />
                  バーコードスキャン検品
                </CardTitle>
                <CardDescription>
                  届いた商品の JAN をスキャン（または入力して Enter）すると、該当明細の検品数量が 1 点ずつ加算されます。
                </CardDescription>
              </CardHeader>
              <CardContent className="flex flex-col gap-3">
                <form className="flex flex-col gap-2 sm:flex-row sm:items-end" onSubmit={handleScan}>
                  <div className="flex w-full flex-col gap-1.5">
                    <Label htmlFor="scan">バーコード / JAN をスキャン</Label>
                    <div className="relative">
                      <IconBarcode
                        className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground"
                        aria-hidden="true"
                      />
                      <Input
                        id="scan"
                        ref={scanRef}
                        value={scanInput}
                        onChange={(e) => setScanInput(e.target.value)}
                        placeholder="ここにスキャン…（例 4901234567894）"
                        autoComplete="off"
                        inputMode="numeric"
                        className="pl-9 font-mono tabular-nums"
                      />
                    </div>
                  </div>
                  <Button type="submit" variant="secondary" disabled={!scanInput.trim()} className="shrink-0">
                    <IconScan className="h-4 w-4" aria-hidden="true" />
                    検品
                  </Button>
                </form>

                {/* announced scan result */}
                <div role="status" aria-live="assertive">
                  {scanResult ? (
                    <Alert variant={scanResult.kind === "match" ? "success" : "destructive"}>
                      {scanResult.kind === "match" ? (
                        <IconCircleCheck className="h-4 w-4" aria-hidden="true" />
                      ) : (
                        <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
                      )}
                      <AlertTitle as="h3">
                        {scanResult.kind === "match" ? "検品しました" : "発注に無い商品"}
                      </AlertTitle>
                      <AlertDescription>{scanResult.message}</AlertDescription>
                    </Alert>
                  ) : null}
                </div>

                {/* scan feed */}
                {scanFeed.length ? (
                  <div className="flex flex-col gap-1.5">
                    <p className="flex items-center gap-1.5 text-xs font-medium text-muted-foreground">
                      <IconList className="h-3.5 w-3.5" aria-hidden="true" />
                      最近のスキャン
                    </p>
                    <ul className="flex flex-col gap-1">
                      {scanFeed.map((s) => (
                        <li
                          key={s.id}
                          className="flex items-center justify-between gap-2 rounded-md border bg-muted/30 px-2.5 py-1.5 text-xs"
                        >
                          <span className="flex items-center gap-2 truncate">
                            <Badge variant={s.kind === "match" ? "success" : "destructive"}>
                              {s.kind === "match" ? "検品" : "対象外"}
                            </Badge>
                            <span className="truncate font-medium">{s.label}</span>
                          </span>
                          <span className="shrink-0 font-mono tabular-nums text-muted-foreground">
                            {s.detail}
                          </span>
                        </li>
                      ))}
                    </ul>
                  </div>
                ) : null}
              </CardContent>
            </Card>
          ) : null}

          {/* receiving lines grid */}
          <Card>
            <CardHeader className="pb-3">
              <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                <IconClipboardCheck className="h-5 w-5" aria-hidden="true" />
                入荷明細
              </CardTitle>
              <CardDescription>
                差異 = 検品数量 − 発注数量。不足・過剰、または不良がある行は差異理由が必要です。生鮮品はロット番号・賞味期限を取得します。
              </CardDescription>
            </CardHeader>
            <CardContent>
              <EditableDataTable
                columns={columns}
                rows={lines}
                getRowId={(l) => l.id}
                rowLabel={(i) => lines[i]?.name ?? `行 ${i + 1}`}
                getRowError={
                  showErrors ? (row) => problemByLine.get(row.id) : undefined
                }
                renderFooterCell={footerCell}
                caption="入荷明細 — スキャンで検品数量が加算され、差異が自動計算されます。"
              />
            </CardContent>
          </Card>

          {/* discrepancy gate — revealed when any line differs from PO */}
          <RevealSection open={!accepted && discCount > 0} label="差異処理">
            <Alert variant="warning">
              <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
              <AlertTitle as="h2">差異処理が必要です（{discCount} 件）</AlertTitle>
              <AlertDescription>
                検品数量が発注数量と一致しない行、または不良が記録された行があります。
                各行の「差異理由」を選択するまで入荷確定はできません。
              </AlertDescription>
            </Alert>
          </RevealSection>

          {/* validation summary on accept attempt */}
          <RevealSection open={showErrors && problems.length > 0} label="入荷確定エラー">
            <Alert variant="destructive">
              <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
              <AlertTitle as="h2">入荷確定できません（{problems.length} 件）</AlertTitle>
              <AlertDescription>
                <ul className="ml-4 list-disc">
                  {problems.map((p) => (
                    <li key={`${p.lineId}-${p.message}`}>{p.message}</li>
                  ))}
                </ul>
              </AlertDescription>
            </Alert>
          </RevealSection>

          {/* completion confirmation */}
          {accepted ? (
            <Alert variant="success">
              <IconCircleCheck className="h-4 w-4" aria-hidden="true" />
              <AlertTitle as="h2">受領完了</AlertTitle>
              <AlertDescription>
                {po.poNumber}（{po.supplier}）の入荷を確定しました。検品 {formatNumber(inspected)} 点 ·
                差異 {formatNumber(discCount)} 件 · 仕入原価 {yen(cost)} を在庫に受領しました。
              </AlertDescription>
            </Alert>
          ) : null}

          {/* actions */}
          <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
            <div className="text-xs text-muted-foreground" aria-live="polite">
              {accepted
                ? "この受領は確定済みです（読み取り専用）。"
                : savedAt
                  ? `一時保存しました（${savedAt}）。`
                  : `検品 ${formatNumber(inspected)} / 発注 ${formatNumber(ordered)} 点 · 差異 ${discCount} 件`}
            </div>
            <div className="flex flex-wrap items-center gap-2">
              {accepted ? (
                <>
                  <Button variant="outline" onClick={() => setReceiptOpen(true)}>
                    <IconPrinter className="h-4 w-4" aria-hidden="true" />
                    受領書を印刷
                  </Button>
                  <Button variant="secondary" onClick={reset}>
                    新しい入荷を検品
                  </Button>
                </>
              ) : (
                <>
                  <Button
                    variant="ghost"
                    onClick={() => {
                      setSavedAt(
                        new Date().toLocaleTimeString("ja-JP", {
                          hour: "2-digit",
                          minute: "2-digit",
                        }),
                      );
                    }}
                  >
                    <IconDeviceFloppy className="h-4 w-4" aria-hidden="true" />
                    一時保存
                  </Button>
                  <Button variant="outline" onClick={() => setReceiptOpen(true)}>
                    <IconPrinter className="h-4 w-4" aria-hidden="true" />
                    受領サマリ
                  </Button>
                  <Button
                    variant="success"
                    onClick={attemptAccept}
                    disabled={inspected === 0}
                  >
                    <IconPackageImport className="h-4 w-4" aria-hidden="true" />
                    入荷確定
                  </Button>
                </>
              )}
            </div>
          </div>
        </>
      ) : null}

      {/* receipt / summary preview */}
      <Dialog open={receiptOpen} onOpenChange={setReceiptOpen}>
        <DialogContent className="max-h-[85vh] overflow-y-auto sm:max-w-lg">
          <DialogHeader>
            <DialogTitle>受領サマリ — {po?.poNumber}</DialogTitle>
            <DialogDescription>
              {po?.supplier} · 入荷予定 {po?.expectedDate} · {po?.warehouse}
            </DialogDescription>
          </DialogHeader>
          <div className="flex flex-col gap-3 text-sm">
            <ul className="flex flex-col divide-y">
              {lines.map((l) => {
                const s = lineState(l);
                const d = lineDelta(l);
                return (
                  <li key={l.id} className="flex items-center justify-between gap-3 py-2">
                    <span className="flex flex-col">
                      <span className="font-medium">{l.name}</span>
                      <span className="font-mono text-xs text-muted-foreground tabular-nums">
                        検品 {l.inspected} / 発注 {l.ordered}
                        {l.perishable && l.lot ? ` · Lot ${l.lot}` : ""}
                        {l.perishable && l.expiry ? ` · 賞味 ${l.expiry}` : ""}
                      </span>
                    </span>
                    <span className="flex shrink-0 items-center gap-2">
                      {d !== 0 || l.quality === "damaged" ? (
                        <Delta
                          value={d}
                          format={(n) => (n === 0 ? "0" : formatNumber(n, { signed: true }))}
                          labels={{ positive: "過剰", negative: "不足", zero: "一致" }}
                          showLabel
                          tones={{ positive: "warning", negative: "warning", zero: "success" }}
                        />
                      ) : null}
                      <Badge variant={STATE_BADGE_VARIANT[s]}>{LINE_STATE_LABEL[s]}</Badge>
                    </span>
                  </li>
                );
              })}
            </ul>
            <Separator />
            <dl className="flex flex-col gap-1.5">
              <div className="flex justify-between">
                <dt className="text-muted-foreground">発注合計</dt>
                <dd className="tabular-nums">{formatNumber(ordered)} 点</dd>
              </div>
              <div className="flex justify-between">
                <dt className="text-muted-foreground">検品合計</dt>
                <dd className="tabular-nums">{formatNumber(inspected)} 点</dd>
              </div>
              <div className="flex justify-between">
                <dt className="text-muted-foreground">差異件数</dt>
                <dd className="tabular-nums">{formatNumber(discCount)} 件</dd>
              </div>
              <div className="flex justify-between font-semibold">
                <dt>検品 仕入原価</dt>
                <dd className="tabular-nums">{yen(cost)}</dd>
              </div>
            </dl>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setReceiptOpen(false)}>
              <IconX className="h-4 w-4" aria-hidden="true" />
              閉じる
            </Button>
            <Button variant="secondary" onClick={() => window.print()}>
              <IconPrinter className="h-4 w-4" aria-hidden="true" />
              印刷
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </main>
  );
}
